28	// Modal bottom sheet per docs/design.md §3.3 ("Bottom sheet (80% height)") +
29	// §6 inventory (children, snapPoints). Slides up on open with SPRING_SNAPPY per
30	// §1.4 line 99. Drag-to-dismiss via react-native-gesture-handler PanGesture:
31	// snap to the nearest provided snap point, or dismiss when pulled past the
32	// lowest snap + threshold or flung downward.
33	//
34	// snapPoints are fractions of screen height. The FIRST entry is the initial
35	// (and largest) snap — sheet height is set from it. Additional smaller entries
36	// create peek positions the user can drag to.
37	const DISMISS_VELOCITY = 600; // px/s — fling-dismiss threshold
38	const DISMISS_DRAG_OVERSHOOT = 0.25; // extra drag past lowest snap before dismissing (as fraction of sheetHeight)
39	
40	export type BottomSheetProps = {
41	  visible: boolean;
42	  onDismiss: () => void;
43	  children: React.ReactNode;
44	  snapPoints?: readonly number[];
45	  style?: StyleProp<ViewStyle>;
46	  accessibilityLabel?: string;
47	  testID?: string;
48	};
49	
50	export function BottomSheet({
51	  visible,
52	  onDismiss,
53	  children,
54	  snapPoints = [0.8],
55	  style,
56	  accessibilityLabel,
57	  testID,
58	}: BottomSheetProps) {
59	  const reduced = useReducedMotion();
60	  const { height: screenHeight } = useWindowDimensions();
61	
62	  const { sheetHeight, snapOffsets } = useMemo(() => {
63	    const sorted = [...snapPoints]
64	      .map((p) => clamp(p, 0.2, 0.95))
65	      .sort((a, b) => b - a);
66	    const primary = sorted[0] ?? 0.8;
67	    const h = screenHeight * primary;
68	    // snapOffsets[0] is always 0 (fully shown at primary snap). Subsequent
69	    // entries are positive translateY offsets sliding the sheet down for peeks.
70	    const offsets = sorted.map((p) => h * (1 - p / primary));
71	    return { sheetHeight: h, snapOffsets: offsets };
72	  }, [snapPoints, screenHeight]);
73	
74	  const translateY = useSharedValue(sheetHeight);
75	  const backdropOpacity = useSharedValue(0);
76	  const gestureStart = useSharedValue(0);
77	
78	  useEffect(() => {
79	    if (visible) {
80	      translateY.value = withSpring(0, withReducedMotion<WithSpringConfig>(SPRING_SNAPPY, reduced));
81	      backdropOpacity.value = withTiming(1, { duration: reduced ? 0 : 180 });
82	    } else {
83	      translateY.value = withSpring(
84	        sheetHeight,
85	        withReducedMotion<WithSpringConfig>(SPRING_SNAPPY, reduced),
86	      );
87	      backdropOpacity.value = withTiming(0, { duration: reduced ? 0 : 160 });
88	    }
89	  }, [visible, reduced, sheetHeight, translateY, backdropOpacity]);
90	
91	  // Keep the offscreen parking spot in sync with sheetHeight when hidden, so a
92	  // rotation-driven height change while closed doesn't leave the sheet peeking.
93	  useEffect(() => {
94	    if (!visible) {
95	      translateY.value = sheetHeight;
96	    }
97	  }, [visible, sheetHeight, translateY]);
98	
99	  const pan = useMemo(
100	    () =>
101	      Gesture.Pan()
102	        .onStart(() => {
103	          gestureStart.value = translateY.value;
104	        })
105	        .onUpdate((e) => {
106	          translateY.value = Math.max(0, gestureStart.value + e.translationY);
107	        })
108	        .onEnd((e) => {
109	          const final = translateY.value;
110	          const largestOffset = snapOffsets[snapOffsets.length - 1] ?? 0;
111	          const shouldDismiss =
112	            final > largestOffset + sheetHeight * DISMISS_DRAG_OVERSHOOT ||
113	            e.velocityY > DISMISS_VELOCITY;
114	          if (shouldDismiss) {
115	            runOnJS(onDismiss)();
116	            return;
117	          }
118	          let nearest = snapOffsets[0] ?? 0;
119	          let bestDist = Math.abs(final - nearest);
120	          for (const o of snapOffsets) {
121	            const d = Math.abs(final - o);
122	            if (d < bestDist) {
123	              bestDist = d;
124	              nearest = o;
125	            }
126	          }
127	          translateY.value = withSpring(
128	            nearest,
129	            withReducedMotion<WithSpringConfig>(SPRING_SNAPPY, reduced),
130	          );
131	        }),
132	    [gestureStart, translateY, snapOffsets, sheetHeight, reduced, onDismiss],
133	  );
134	
135	  const sheetAnimatedStyle = useAnimatedStyle(() => ({
136	    transform: [{ translateY: translateY.value }],
137	  }));
138	
139	  const backdropAnimatedStyle = useAnimatedStyle(() => ({
140	    opacity: backdropOpacity.value * 0.45,
141	  }));
142	
143	  return (
144	    <Modal
145	      visible={visible}
146	      transparent
147	      onRequestClose={onDismiss}
148	      animationType="none"
149	      statusBarTranslucent
150	      testID={testID}
151	    >
152	      {/* New GestureHandlerRootView inside Modal — on Android, Modal opens a new
153	          window that does not inherit the root handler from app/_layout.tsx. */}
154	      <GestureHandlerRootView style={styles.root}>
155	        <Animated.View
156	          pointerEvents="box-none"
157	          style={[styles.backdrop, backdropAnimatedStyle]}
158	        >
159	          <Pressable
160	            style={StyleSheet.absoluteFill}
161	            onPress={onDismiss}
162	            accessible={false}
163	            importantForAccessibility="no"
164	          />
165	        </Animated.View>
166	        <GestureDetector gesture={pan}>
167	          <Animated.View
168	            style={[styles.sheet, { height: sheetHeight }, shadows.hard, sheetAnimatedStyle, style]}
169	            accessibilityViewIsModal
170	            accessibilityLabel={accessibilityLabel}
171	          >
172	            <View style={styles.handle} />
173	            <View style={styles.content}>{children}</View>
174	          </Animated.View>
175	        </GestureDetector>
176	      </GestureHandlerRootView>
177	    </Modal>
178	  );
179	}
